                          ВидыЗначений.ВидДоступа       = НаборыЗначений.ВидДоступа
                        И ВидыЗначений.ЗначениеДоступа  = НаборыЗначений.ЗначениеДоступа
                        И ВидыЗначений.ТолькоВидДоступа = Истина
