     )
    #Иначе
     (
        #Если "#Параметр(15)" = "Пользователи" #Тогда
          #Если &ТекущийВнешнийПользователь = Значение(Справочник.ВнешниеПользователи.ПустаяСсылка) #Тогда
            Истина В
