#ИначеЕсли НЕ &ОграничиватьДоступПоВиду#Параметр(18) = "" #Тогда

    #Если &ОграничиватьДоступПоВиду#Параметр(18) = "ЧерезПраваПоЗначениямДоступа" #Тогда
     (
    НЕ Истина В // Проверка, что по виду доступа пользователь ограничивается.
