                      ПользователиИГруппыПользователей.ВидДоступа      = Значение(ПланВидовХарактеристик.ВидыДоступа.ПустаяСсылка)
                    И ПользователиИГруппыПользователей.ЗначениеДоступа = &ТекущийПользователь
                #Иначе
